import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import Logo from './Logo';
import './Sidebar.css';

export default function Sidebar({ role = 'host', user = { name: 'Premium Host', plan: 'Premium Host' } }) {
  const location = useLocation();
  const navigate = useNavigate();

  const hostLinks = [
    { href: '/host/dashboard', label: 'Dashboard', icon: <GridIcon /> },
    { href: '/host/home', label: 'Events', icon: <CalIcon /> },
    { href: '/host/guest-list', label: 'RSVP Manager', icon: <UsersIcon /> },
    { href: '/gallery', label: 'Gallery', icon: <GalleryIcon /> },
    { href: '/host/admin-roles', label: 'Check-In', icon: <CheckIcon /> },
  ];

  const guestLinks = [
    { href: '/guest/dashboard', label: 'Dashboard', icon: <GridIcon /> },
    { href: '/timeline', label: 'Timeline', icon: <TimelineIcon /> },
    { href: '/gallery', label: 'Gallery', icon: <GalleryIcon /> },
    { href: '/scan-qr', label: 'Scan QR', icon: <QRIcon /> },
  ];

  const links = role === 'host' ? hostLinks : guestLinks;

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <Logo size="sm" />
      </div>
      <div className="sidebar-user">
        <div className="sidebar-avatar">
          <img src="https://placehold.co/36x36/7C3AED/white?text=PH" alt="User avatar" className="avatar" width={36} height={36} />
        </div>
        <div>
          <div className="sidebar-user-name">{user.name}</div>
          <div className="sidebar-user-plan">{user.plan}</div>
        </div>
      </div>
      <nav className="sidebar-nav">
        {links.map((l, i) => (
          <Link key={i} to={l.href} className={`sidebar-link ${location.pathname === l.href ? 'active' : ''}`}>
            <span className="sidebar-icon">{l.icon}</span>
            {l.label}
          </Link>
        ))}
      </nav>
      <div className="sidebar-bottom">
        <button className="sidebar-link sidebar-create" onClick={() => navigate('/host/create-event')}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><path d="M12 8v8M8 12h8"/></svg>
          Create New Event
        </button>
        <div className="sidebar-user-bottom">
          <img src="https://placehold.co/32x32/7C3AED/white?text=A" alt="User" className="avatar" width={32} height={32} />
          <span className="sidebar-user-name2">Amara</span>
        </div>
      </div>
    </aside>
  );
}

function GridIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>;
}
function CalIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/></svg>;
}
function UsersIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/></svg>;
}
function GalleryIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="m21 15-5-5L5 21"/></svg>;
}
function CheckIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>;
}
function TimelineIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>;
}
function QRIcon() {
  return <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>;
}
